t.script:
                //
(function () {
    'use strict';
    var INTERVAL = 15000;
    var A = [
        { key: 'open_tickets',     sel: '[data-key="open_tickets"] .stat-value' },
        { key: 'total_tickets',    sel: '[data-key="total_tickets"] .stat-value' },
        { key: 'high_priority',    sel: '[data-key="high_priority"] .stat-value' },
        { key: 'urgent',           sel: '[data-key="urgent"] .stat-value' },
        { key: 'avg_open_hours',   sel: '[data-key="avg_open_hours"] .stat-value' },
        { key: 'total_hours',      sel: '[data-key="total_hours"] .stat-value' },
        { key: 'avg_high_hours',   sel: '[data-key="avg_high_hours"] .stat-value' },
        { key: 'avg_urgent_hours', sel: '[data-key="avg_urgent_hours"] .stat-value' },
        { key: 'resolved_tickets', sel: '[data-key="resolved_tickets"] .stat-value' },
        { key: 'solve_rate',       sel: '[data-key="solve_rate"] .stat-value', sfx: '%' },
        { key: 'high_resolved',    sel: '[data-key="high_resolved"] .stat-value' },
        { key: 'urgent_resolved',  sel: '[data-key="urgent_resolved"] .stat-value' }
    ];
    var P = [
        { key: 'today_closed',       sel: '[data-key="today_closed"] .performance-value' },
        { key: 'avg_resolve_rate',   sel: '[data-key="avg_resolve_rate"] .performance-value', sfx: '%' },
        { key: 'daily_target',       sel: '[data-key="daily_target"] .performance-value', sfx: '%' },
        { key: 'achievement',        sel: '[data-key="achievement"] .performance-value', sfx: '%' },
        { key: 'sample_performance', sel: '[data-key="sample_performance"] .score-badge', sfx: '%' }
    ];
    function upd(sel, val, sfx) { var el = document.querySelector(sel); if (el) el.textContent = val + (sfx || ''); }
    function flash(sel) {
        var el = document.querySelector(sel);
        if (el) { el.style.transition = 'color 0.3s'; el.style.color = '#0284c7'; setTimeout(function () { el.style.color = ''; }, 600); }
    }
    function updBar(v) {
        var b = document.querySelector('.progress-bar');
        if (b) { b.style.width = v + '%'; b.className = 'progress-bar ' + (v >= 80 ? 'bg-success' : 'bg-warning'); }
    }
    function updBarLabel(v) {
        var ls = document.querySelectorAll('.progress-label span');
        if (ls.length >= 2) ls[1].textContent = v + '%';
    }
    function updTime() {
        var t = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        document.querySelectorAll('.last-updated').forEach(function (el) { el.innerHTML = '<i class="bi bi-clock me-1"></i>Updated at ' + t; });
    }
    function run() {
        fetch('/customer_support/dashboard/analytics', { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { if (!r.ok) throw new Error(r.status); return r.json(); })
        .then(function (d) {
            var a = d.analytics || {}, p = d.performance || {};
            A.forEach(function (i) { var v = a[i.key]; if (v !== undefined) { upd(i.sel, v, i.sfx || ''); flash(i.sel); } });
            P.forEach(function (i) { var v = p[i.key]; if (v !== undefined) upd(i.sel, v, i.sfx || ''); });
            if (p.achievement !== undefined) { updBar(p.achievement); updBarLabel(p.achievement); }
            updTime();
        })
        .catch(function (e) { console.warn('Analytics refresh failed:', e); });
    }
    document.addEventListener('DOMContentLoaded', function () { run(); setInterval(run, INTERVAL); });
})();
                //

                //
document.addEventListener('DOMContentLoaded', function () {

    // ── AUTO-DISMISS ALERTS ───────────────────────────────────────────────
    setTimeout(function () {
        document.querySelectorAll('.alert').forEach(function (a) {
            try { new bootstrap.Alert(a).close(); } catch (e) { a.style.display = 'none'; }
        });
    }, 5000);

    // ── KANBAN COUNTS ─────────────────────────────────────────────────────
    function updatePortalCounts() {
        ['new', 'in_progress', 'resolved', 'closed'].forEach(function (state) {
            var col = document.getElementById('portal-col-' + state);
            var countEl = document.getElementById('portal-count-' + state);
            if (col && countEl) countEl.textContent = col.querySelectorAll('.kanban-card').length;
        });
    }
    updatePortalCounts();

    // ── PAGE SWITCHING ────────────────────────────────────────────────────
    var pages = {
        overview:  document.getElementById('portal-overview-page'),
        kanban:    document.getElementById('portal-kanban-page'),
        reporting: document.getElementById('portal-reporting-page')
    };
    var kanbanBtn = document.getElementById('portalKanbanBtn');

    function hideAllPages() {
        Object.keys(pages).forEach(function (k) { if (pages[k]) pages[k].style.display = 'none'; });
    }
    function setActiveNav(navId, isKanban) {
        document.querySelectorAll('.header-nav .nav-link').forEach(function (l) { l.classList.remove('active'); });
        var el = document.getElementById(navId);
        if (el) el.classList.add('active');
        if (kanbanBtn) kanbanBtn.classList.toggle('active', !!isKanban);
    }
    function showOverview()  { hideAllPages(); pages.overview.style.display = 'block';   setActiveNav('portalOverviewNav', false); }
    function showKanban()    { hideAllPages(); pages.kanban.style.display = 'block';     setActiveNav('portalTicketsNav', true);  updatePortalCounts(); }
    function showReporting() {
        hideAllPages(); pages.reporting.style.display = 'block';
        setActiveNav('portalReportingNav', false);
        syncDayFilterUI();
        loadReportData(currentDays);
    }

    var overviewNav = document.getElementById('portalOverviewNav');
    if (overviewNav) overviewNav.addEventListener('click', function (e) { e.preventDefault(); showOverview(); });
    var ticketsNav = document.getElementById('portalTicketsNav');
    if (ticketsNav) ticketsNav.addEventListener('click', function (e) {
        e.preventDefault();
        window.location.href = '/customer_support/tickets';
    });
    var reportingNav = document.getElementById('portalReportingNav');
    if (reportingNav) reportingNav.addEventListener('click', function (e) { e.preventDefault(); showReporting(); });
    var reportActionCard = document.getElementById('portalReportActionCard');
    if (reportActionCard) reportActionCard.addEventListener('click', function (e) { e.preventDefault(); showReporting(); });
    var listBtn = document.getElementById('portalListBtn');
    if (listBtn) listBtn.addEventListener('click', function () { window.location.href = '/customer_support/tickets'; });
    var kanbanActiveBtn = document.getElementById('portalKanbanActiveBtn');
    if (kanbanActiveBtn) kanbanActiveBtn.addEventListener('click', function () { showKanban(); });

    document.querySelectorAll('#portal-kanban-page .kanban-card').forEach(function (card) {
        card.addEventListener('click', function () {
            var id = this.getAttribute('data-ticket-id');
            if (id) window.location.href = '/customer_support/ticket/' + id;
        });
    });
    document.querySelectorAll('.action-card').forEach(function (card) {
        card.addEventListener('click', function (e) {
            var href = this.getAttribute('href');
            if (!href || href === '#' || href.endsWith('#')) {
                e.preventDefault();
                var self = this;
                self.style.transform = 'scale(0.95)';
                setTimeout(function () { self.style.transform = ''; }, 150);
            }
        });
    });

    // ── NOTIFICATION BELL ─────────────────────────────────────────────────
    var bell      = document.getElementById('portalNotifBell');
    var dropdown  = document.getElementById('portalNotifDropdown');
    var badge     = document.getElementById('portalNotifBadge');
    var notifList = document.getElementById('portalNotifList');

    if (bell && dropdown) {
        bell.addEventListener('click', function (e) { e.stopPropagation(); dropdown.classList.toggle('open'); });
        document.addEventListener('click', function () { dropdown.classList.remove('open'); });
        dropdown.addEventListener('click', function (e) { e.stopPropagation(); });
    }
    var markReadBtn = document.getElementById('portalMarkRead');
    if (markReadBtn) {
        markReadBtn.addEventListener('click', function () {
            fetch('/customer_support/customer/notifications/mark_read', { method: 'POST', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
            .then(function () {
                if (badge) { badge.classList.add('d-none'); badge.textContent = '0'; }
                if (notifList) { notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>All caught up!</div>'; }
            })
            .catch(function (e) { console.warn('Mark read failed:', e); });
        });
    }
    var viewTicketsLink = document.getElementById('portalNotifViewTickets');
    if (viewTicketsLink) {
        viewTicketsLink.addEventListener('click', function (e) {
            e.preventDefault();
            if (dropdown) dropdown.classList.remove('open');
            showKanban();
        });
    }
    function sanitise(str) { var d = document.createElement('div'); d.textContent = String(str || ''); return d.innerHTML; }
    function renderNotifications(items) {
        if (!notifList) return;
        if (!items || !items.length) {
            notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>No new notifications</div>';
            if (badge) badge.classList.add('d-none');
            return;
        }
        if (badge) { badge.textContent = items.length; badge.classList.remove('d-none'); }
        notifList.innerHTML = items.map(function (n) {
            var href = n.ticket_id ? '/customer_support/ticket/' + encodeURIComponent(n.ticket_id) : '#';
            var cls  = sanitise(n.cls  || 'status');
            var icon = sanitise(n.icon || 'bi-bell-fill');
            var msg  = sanitise(n.message || '');
            var time = sanitise(n.time   || '');
            return '<a class="notif-item" href="' + href + '">'
                + '<div class="notif-icon-wrap ' + cls + '"><i class="bi ' + icon + '"></i></div>'
                + '<div class="notif-body"><div class="notif-title">' + msg + '</div><div class="notif-time">' + time + '</div></div>'
                + '<div class="notif-dot ' + cls + '"></div></a>';
        }).join('');
    }
    function loadNotifications() {
        fetch('/customer_support/customer/notifications', { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { return r.json(); })
        .then(function (data) { renderNotifications(data.notifications || []); })
        .catch(function () { renderNotifications([]); });
    }
    loadNotifications();
    setInterval(loadNotifications, 30000);

    // ── REPORTING ─────────────────────────────────────────────────────────
    var reportFetchInFlight = false;
    var currentDays    = 30;
    var chartInstances = {};

    function syncDayFilterUI() {
        document.querySelectorAll('#reportDayFilter .day-btn').forEach(function (b) {
            b.classList.toggle('active', parseInt(b.getAttribute('data-days'), 10) === currentDays);
        });
    }
    document.querySelectorAll('#reportDayFilter .day-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            currentDays = parseInt(this.getAttribute('data-days'), 10);
            syncDayFilterUI();
            loadReportData(currentDays);
        });
    });
    function destroyChart(id) {
        if (chartInstances[id]) { chartInstances[id].destroy(); delete chartInstances[id]; }
        var canvas = document.getElementById(id);
        if (canvas) { var ctx = canvas.getContext('2d'); if (ctx) ctx.clearRect(0, 0, canvas.width, canvas.height); }
    }
    function loadReportData(days) {
        if (reportFetchInFlight) return;
        reportFetchInFlight = true;
        var loadingEl = document.getElementById('reportLoading');
        var contentEl = document.getElementById('reportContent');
        if (loadingEl) { loadingEl.style.display = 'flex'; loadingEl.innerHTML = '<div class="spinner"></div><span>Loading your report...</span>'; }
        if (contentEl) contentEl.style.display = 'none';
        fetch('/customer_support/customer/reporting?days=' + days, { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { return r.json(); })
        .then(function (data) {
            reportFetchInFlight = false;
            if (!data.success) throw new Error('API error');
            renderReport(data);
            if (loadingEl) loadingEl.style.display = 'none';
            if (contentEl) contentEl.style.display = 'block';
            var pd = document.getElementById('reportPrintDate');
            if (pd) pd.textContent = new Date().toLocaleDateString() + ' (Last ' + days + ' days)';
        })
        .catch(function (e) {
            reportFetchInFlight = false;
            console.error('Reporting fetch failed:', e);
            if (loadingEl) {
                loadingEl.style.display = 'flex';
                loadingEl.innerHTML = '<i class="bi bi-exclamation-triangle" style="color:#dc2626;font-size:1.5rem;margin-right:.5rem;"></i><span style="color:#dc2626;">Could not load report data. Please try again.</span>';
            }
        });
    }

    function renderReport(data) {
        var kpis = data.kpis || {};
        var rate = kpis.resolve_rate || 0;
        document.getElementById('rKpiTotal').textContent    = kpis.total    || 0;
        document.getElementById('rKpiResolved').textContent = kpis.resolved || 0;
        document.getElementById('rKpiOpen').textContent     = kpis.open     || 0;
        document.getElementById('rKpiAvgHours').textContent = kpis.avg_resolution_hours || 0;
        var rateEl = document.getElementById('rKpiRate');
        rateEl.textContent = rate + '%';
        rateEl.className   = 'report-kpi-value ' + (rate >= 80 ? 'green' : rate >= 50 ? 'amber' : 'red');

        destroyChart('chartTimeline');
        var tl = data.timeline || [];
        chartInstances['chartTimeline'] = new Chart(document.getElementById('chartTimeline').getContext('2d'), {
            type: 'line',
            data: {
                labels: tl.map(function (d) { return d.date; }),
                datasets: [{ label: 'Tickets Submitted', data: tl.map(function (d) { return d.count; }),
                    borderColor: '#0284c7', backgroundColor: 'rgba(2,132,199,0.1)',
                    borderWidth: 2, pointRadius: tl.length <= 14 ? 4 : 2, pointBackgroundColor: '#0284c7', fill: true, tension: 0.35 }]
            },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } },
                scales: {
                    x: { ticks: { color: '#475569', font: { size: 10 }, maxTicksLimit: 10, maxRotation: 45 }, grid: { color: 'rgba(12,74,110,0.08)' } },
                    y: { ticks: { color: '#475569', font: { size: 10 }, stepSize: 1, precision: 0 }, grid: { color: 'rgba(12,74,110,0.08)' }, beginAtZero: true }
                }
            }
        });

        destroyChart('chartStatus');
        var st = data.status_breakdown || {};
        var stLabels = Object.keys(st);
        var stColors = { 'New': '#3b82f6', 'In Progress': '#f59e0b', 'Resolved': '#22c55e', 'Closed': '#94a3b8' };
        chartInstances['chartStatus'] = new Chart(document.getElementById('chartStatus').getContext('2d'), {
            type: 'doughnut',
            data: { labels: stLabels, datasets: [{ data: stLabels.map(function (k) { return st[k]; }),
                backgroundColor: stLabels.map(function (l) { return stColors[l] || '#64748b'; }), borderWidth: 0, hoverOffset: 8 }] },
            options: { responsive: true, maintainAspectRatio: false, cutout: '62%',
                plugins: { legend: { position: 'bottom', labels: { color: '#475569', font: { size: 11 }, padding: 16 } } } }
        });

        destroyChart('chartPriority');
        var pr = data.priority_breakdown || {};
        var prLabels = ['Low', 'Medium', 'High', 'Urgent'];
        chartInstances['chartPriority'] = new Chart(document.getElementById('chartPriority').getContext('2d'), {
            type: 'bar',
            data: { labels: prLabels, datasets: [{ label: 'Tickets', data: prLabels.map(function (k) { return pr[k] || 0; }),
                backgroundColor: ['#22c55e', '#3b82f6', '#f59e0b', '#ef4444'], borderRadius: 8, borderSkipped: false }] },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } },
                scales: {
                    x: { ticks: { color: '#475569', font: { size: 11 } }, grid: { display: false } },
                    y: { ticks: { color: '#475569', font: { size: 10 }, stepSize: 1, precision: 0 }, grid: { color: 'rgba(12,74,110,0.08)' }, beginAtZero: true }
                }
            }
        });

        destroyChart('chartResolveTrend');
        var rt = data.resolve_trend || [];
        chartInstances['chartResolveTrend'] = new Chart(document.getElementById('chartResolveTrend').getContext('2d'), {
            type: 'line',
            data: {
                labels: rt.map(function (d) { return d.week; }),
                datasets: [{ label: 'Resolve Rate %', data: rt.map(function (d) { return d.rate; }),
                    borderColor: '#059669', backgroundColor: 'rgba(5,150,105,0.08)',
                    borderWidth: 2.5, pointRadius: 5, pointBackgroundColor: '#059669', fill: true, tension: 0.3 }]
            },
            options: { responsive: true, maintainAspectRatio: false,
                plugins: { legend: { display: false }, tooltip: { callbacks: { label: function (ctx) { return ctx.parsed.y + '%'; } } } },
                scales: {
                    x: { ticks: { color: '#475569', font: { size: 11 } }, grid: { color: 'rgba(12,74,110,0.08)' } },
                    y: { ticks: { color: '#475569', font: { size: 10 }, callback: function (v) { return v + '%'; } }, grid: { color: 'rgba(12,74,110,0.08)' }, beginAtZero: true, max: 100 }
                }
            }
        });
    }

    // ── BACK BUTTON TRAP ──────────────────────────────────────────────────
    var logoutModal    = document.getElementById('logoutWarningModal');
    var modalStayBtn   = document.getElementById('modalStayBtn');
    var modalLogoutBtn = document.getElementById('modalLogoutBtn');

    var initParams = new URLSearchParams(window.location.search);
    if (!initParams.get('view')) {
        history.pushState(null, null, window.location.href);
    }
    window.addEventListener('popstate', function () {
        var params = new URLSearchParams(window.location.search);
        if (params.get('view')) return;
        history.pushState(null, null, window.location.href);
        if (logoutModal) logoutModal.classList.add('show');
    });
    window.addEventListener('pageshow', function (e) {
        if (e.persisted) {
            var showParams = new URLSearchParams(window.location.search);
            if (!showParams.get('view')) history.pushState(null, null, window.location.href);
        }
    });
    if (modalStayBtn)   modalStayBtn.addEventListener('click',   function () { if (logoutModal) logoutModal.classList.remove('show'); });
    if (modalLogoutBtn) modalLogoutBtn.addEventListener('click', function () { window.location.href = '/customer_support/logout_manual'; });
    if (logoutModal)    logoutModal.addEventListener('click',    function (e) { if (e.target === logoutModal) logoutModal.classList.remove('show'); });

    // ── AUTO SWITCH VIEW FROM URL HASH ────────────────────────────────────
    if (window.location.hash === '#reporting') {
        showReporting();
        history.replaceState(null, null, window.location.pathname);
    } else if (window.location.hash === '#kanban') {
        showKanban();
        history.replaceState(null, null, window.location.pathname);
    }
});
